import { useCallback, useEffect, useState } from 'react'

export const useKey = (key: string, keyDownCb = () => {}, keyUpCb = () => {}): boolean => {
  const [pressed, setPressed] = useState(false)
  const match = useCallback((event: any) => key.toLowerCase() === event.key.toLowerCase(), [key])

  const onKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (match(event)) {
        setPressed(true)
        keyDownCb()
      }
    },
    [keyDownCb, match]
  )

  const onKeyUp = useCallback(
    (event: KeyboardEvent) => {
      if (match(event)) {
        setPressed(false)
        keyUpCb()
      }
    },
    [keyUpCb, match]
  )

  useEffect(() => {
    globalThis.addEventListener('keydown', onKeyDown)
    globalThis.addEventListener('keyup', onKeyUp)

    return () => {
      globalThis.removeEventListener('keydown', onKeyDown)
      globalThis.removeEventListener('keyup', onKeyUp)
    }
  }, [key, onKeyDown, onKeyUp])

  return pressed
}

import { useLayoutEffect } from 'react'
import { isMobile } from '../helpers'

export const useLockBodyScroll = (shouldLock = false) => {
  useLayoutEffect(() => {
    document.body.style.overflow = shouldLock ? 'hidden' : 'auto'
    if (isMobile()) {
      document.body.style.height = shouldLock ? '100vh' : 'auto'
    }
    // Re-enable scrolling when component unmounts
    return () => {
      document.body.style.overflow = 'auto'
      if (isMobile()) {
        document.body.style.height = 'auto'
      }
    }
  }, [shouldLock])
}

